1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const LOYALTY_DISCOUNT = -0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT = -0.15;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
35	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type QuoteStep = { op: "quote"; items: Item[] };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	type Step = QuoteStep | ClaimStep;
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	type Policy = { items: Item[]; cap: number };
44	
45	const basePremiumFor = (type: string): number => {
46	  const premium = BASE_PREMIUM[type];
47	  if (premium === undefined) throw new Error(`unknown item type: ${type}`);
48	  return premium;
49	};
50	
51	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
52	
53	const isMainItem = (item: Item): boolean => !isComponent(item);
54	
55	const groupByType = (items: Item[]): Map<string, number> =>
56	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
57	
58	const componentGroupPremium = (type: string, count: number): number =>
59	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
60	
61	const componentsPremium = (items: Item[]): number =>
62	  Array.from(groupByType(items.filter(isComponent)))
63	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
64	
65	const isHighlyEnchanted = (item: Item): boolean =>
66	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
67	
68	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
69	
70	const itemRateAdjustment = (item: Item): number =>
71	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
72	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
73	
74	const itemPremium = (item: Item): number =>
75	  basePremiumFor(item.type) * (1 + itemRateAdjustment(item));
76	
77	type PremiumBreakdown = { base: number; withSurcharges: number };
78	
79	const addBreakdowns = (a: PremiumBreakdown, b: PremiumBreakdown): PremiumBreakdown => ({
80	  base: a.base + b.base,
81	  withSurcharges: a.withSurcharges + b.withSurcharges,
82	});
83	
84	const mainItemBreakdown = (item: Item): PremiumBreakdown => ({
85	  base: basePremiumFor(item.type),
86	  withSurcharges: itemPremium(item),
87	});
88	
89	const componentsBreakdown = (items: Item[]): PremiumBreakdown => {
90	  const total = componentsPremium(items);
91	  return { base: total, withSurcharges: total };
92	};
93	
94	const itemsBreakdown = (items: Item[]): PremiumBreakdown =>
95	  items
96	    .filter(isMainItem)
97	    .map(mainItemBreakdown)
98	    .reduce(addBreakdowns, componentsBreakdown(items));
99	
100	const isLongStanding = (customer: Customer): boolean =>
101	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
102	
103	const policyRateAdjustment = (customer: Customer, isFollowUp: boolean): number =>
104	  rateWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE) +
105	  rateWhen(isLongStanding(customer), LOYALTY_DISCOUNT) +
106	  rateWhen(isFollowUp, FOLLOW_UP_DISCOUNT);
107	
108	const FLOATING_POINT_EPSILON = 1e-9;
109	
110	const roundUpInOurFavor = (amount: number): number =>
111	  Math.ceil(amount - FLOATING_POINT_EPSILON);
112	
113	const policyPremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
114	  const { base, withSurcharges } = itemsBreakdown(items);
115	  return withSurcharges + base * policyRateAdjustment(customer, isFollowUp) + PROCESSING_FEE;
116	};
117	
118	const isFollowUpStep = (stepIndex: number): boolean => stepIndex > 0;
119	
120	const quoteResult = (customer: Customer, items: Item[], stepIndex: number): { premium: number } => ({
121	  premium: roundUpInOurFavor(policyPremium(customer, items, isFollowUpStep(stepIndex))),
122	});
123	
124	const insuranceValueFor = (type: string): number => {
125	  const value = INSURANCE_VALUE[type];
126	  if (value === undefined) throw new Error(`unknown item type: ${type}`);
127	  return value;
128	};
129	
130	const policyInsuranceSum = (items: Item[]): number =>
131	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
132	
133	const damagePayout = (damage: Damage): number =>
134	  Math.max(0, damage.amount - DEDUCTIBLE);
135	
136	const claimResult = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
137	  const rawPayout = incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
138	  const payout = Math.min(rawPayout, policy.cap);
139	  policy.cap -= payout;
140	  return { payout, remainingCap: policy.cap };
141	};
142	
143	const processStep = (customer: Customer, policies: Policy[]) =>
144	  (step: Step, stepIndex: number): unknown => {
145	    if (step.op === "quote") {
146	      policies[stepIndex] = { items: step.items, cap: policyInsuranceSum(step.items) * CAP_MULTIPLIER };
147	      return quoteResult(customer, step.items, stepIndex);
148	    }
149	    return claimResult(policies[step.policy], step.incident);
150	  };
151	
152	export const runScenario = (input: unknown): unknown => {
153	  const { customer, steps } = input as Scenario;
154	  const policies: Policy[] = [];
155	  return { results: steps.map(processStep(customer, policies)) };
156	};
