const claimResult = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
  const rawPayout = incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
  const payout = Math.min(rawPayout, policy.cap);
  policy.cap -= payout;
  return { payout, remainingCap: policy.cap };
};

const processStep = (customer: Customer, policies: Policy[]) =>
  (step: Step, stepIndex: number): unknown => {
    if (step.op === "quote") {
      policies[stepIndex] = { items: step.items, cap: policyInsuranceSum(step.items) * CAP_MULTIPLIER };
      return quoteResult(customer, step.items, stepIndex);
    }
    return claimResult(policies[step.policy], step.incident);
  };

export const runScenario = (input: unknown): unknown => {
  const { customer, steps } = input as Scenario;
  const policies: Policy[] = [];
  return { results: steps.map(processStep(customer, policies)) };
};

