  damages.reduce((sum, d) => sum + damagePayout(d), 0);

const settleClaim = (policy: Policy, incident: Incident): { result: { payout: number; remainingCap: number }; policy: Policy } => {
  const payout = Math.min(totalRawPayout(incident.damages), policy.cap);
  const updated = { ...policy, cap: policy.cap - payout };
  return { result: { payout, remainingCap: updated.cap }, policy: updated };
};

const openPolicy = (items: Item[]): Policy => ({
  items,
  cap: policyInsuranceSum(items) * CAP_MULTIPLIER,
});

type ScenarioState = { policies: Policy[]; results: unknown[] };

const applyStep = (customer: Customer) =>
  (state: ScenarioState, step: Step, stepIndex: number): ScenarioState => {
    if (step.op === "quote") {
      return {
        policies: [...state.policies, openPolicy(step.items)],
        results: [...state.results, quoteResult(customer, step.items, stepIndex)],
      };
    }
    const { result, policy } = settleClaim(state.policies[step.policy], step.incident);
    return {
      policies: state.policies.map((p, i) => (i === step.policy ? policy : p)),
      results: [...state.results, result],
    };
  };

export const runScenario = (input: unknown): unknown => {
  const { customer, steps } = input as Scenario;
  const initial: ScenarioState = { policies: [], results: [] };
  const { results } = steps.reduce(applyStep(customer), initial);
  return { results };
};

